import React, { useState, useEffect, useRef } from 'react';

function App() {
  const [count, setCount] = useState(300);
  const [flag, setFlag] = useState(false);
  const timerRef = useRef(null);  // Persist timer across renders

  const styles = {
    main: { padding: '20px' },
    title: { color: '#5C6AC4' },
  };

  useEffect(() => {
    if (flag) {
      timerRef.current = setInterval(() => {
        setCount((prev) => {
          if (prev <= 1) {     // Stop at 0 or 1
            clearInterval(timerRef.current);
            setFlag(false);
            return 0;          // Or 1
          }
          return prev - 1;
        });
      }, 1000);
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }

    return () => {  // Cleanup
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [flag]);  // Re-run only on flag change

  return (
    <div style={styles.main}>
      <h1 style={styles.title}>{count}</h1>
      <div>
        <button onClick={() => setFlag(true)}>Start</button>
        <button onClick={() => {
          setCount(300);
          setFlag(false);
        }}>Reset</button>
        <button onClick={() => setFlag(false)}>Stop</button>
      </div>
    </div>
  );
}

export default App;

